import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import org.apache.commons.csv.CSVFormat;

class CSVFormatTest {

    @Test
    void testWithQuote_char() {
        // Arrange
        CSVFormat format = CSVFormat.DEFAULT;

        // Act
        CSVFormat result = format.withQuote('"');

        // Assert
        assertNotNull(result);
        assertEquals(Character.valueOf('"'), result.getQuoteCharacter());
        // Original format should remain unchanged (immutability)
        assertEquals(format.getQuoteCharacter(), CSVFormat.DEFAULT.getQuoteCharacter());
    }

    @Test
    void testWithQuote_char_nullQuote() {
        // Arrange
        CSVFormat format = CSVFormat.DEFAULT;

        // Act
        CSVFormat result = format.withQuote('\0'); // char '\0' to test withQuote(Character) with non-printable char

        // Assert
        assertNotNull(result);
        assertEquals(Character.valueOf('\0'), result.getQuoteCharacter());
        assertNotSame(format, result);
    }
}
